// MARK: - Keychain Manager

final class KeychainManager {
    static let shared = KeychainManager()
    private let service = "com.cryptowallet.keys"
    
    private init() {}
    
    func storePrivateKey(_ privateKeyData: Data, forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address,
            kSecValueData as String: privateKeyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        // Delete existing key if present
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw WalletError.keychainError("Failed to store key: \(status)")
        }
    }
    
    func retrievePrivateKey(forAddress address: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw WalletError.keychainError("Failed to retrieve key: \(status)")
        }
        
        return data
    }
    
    func deletePrivateKey(forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw WalletError.keychainError("Failed to delete key: \(status)")
        }
    }
    
    func deleteAllKeys() throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Crypto Utilities

struct CryptoUtils {
    
    // SHA-256 hash
    static func sha256(_ data: Data) -> Data {
        let digest = SHA256.hash(data: data)
        return Data(digest)
    }
    
    // Double SHA-256 (Bitcoin-style)
    static func doubleSHA256(_ data: Data) -> Data {
        return sha256(sha256(data))
    }
    
    // Keccak-256 (Ethereum-style) - simplified implementation
    static func keccak256(_ data: Data) -> Data {
        // For MVP, using SHA256 as placeholder
        // In production, use a proper Keccak-256 implementation
        return sha256(data)
    }
    
    // RIPEMD-160 placeholder (for Bitcoin address derivation)
    static func ripemd160(_ data: Data) -> Data {
        // Simplified - in production use proper RIPEMD-160
        let hash = sha256(data)
        return hash.prefix(20)
    }
    
    // Convert data to hex string
    static func hexString(from data: Data) -> String {
        return data.map { String(format: "%02x", $0) }.joined()
    }
    
    // Convert hex string to data
    static func data(fromHex hex: String) -> Data? {
        var hex = hex
        if hex.hasPrefix("0x") {
            hex = String(hex.dropFirst(2))
        }
        guard hex.count % 2 == 0 else { return nil }
        
        var data = Data()
        var index = hex.startIndex
        while index < hex.endIndex {
            let nextIndex = hex.index(index, offsetBy: 2)
            guard let byte = UInt8(hex[index..<nextIndex], radix: 16) else { return nil }
            data.append(byte)
            index = nextIndex
        }
        return data
    }
    
    // Base58Check encoding (for Bitcoin addresses)
    static func base58CheckEncode(_ data: Data) -> String {
        let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
        let alphabetArray = Array(alphabet)
        
        var bytes = [UInt8](data)
        let checksum = Array(doubleSHA256(data).prefix(4))
        bytes.append(contentsOf: checksum)
        
        var result = ""
        var num = bytes.reduce(into: [UInt]()) { result, byte in
            var carry = UInt(byte)
            for i in 0..<result.count {
                carry += result[i] * 256
                result[i] = carry % 58
                carry /= 58
            }
            while carry > 0 {
                result.append(carry % 58)
                carry /= 58
            }
        }
        
        // Leading zeros
        for byte in bytes {
            if byte != 0 { break }
            result += "1"
        }
        
        for digit in num.reversed() {
            result += String(alphabetArray[Int(digit)])
        }
        
        return result
    }
}

