// MARK: - Transaction Signer

final class TransactionSigner {
    
    static func signTransaction(_ transaction: Transaction, privateKeyData: Data) throws -> Transaction {
        // Serialize transaction data for signing
        let transactionData = try serializeTransaction(transaction)
        let hash = CryptoUtils.sha256(transactionData)
        
        // Sign with P256
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: hash)
        
        var signedTransaction = transaction
        signedTransaction.hash = CryptoUtils.hexString(from: hash)
        signedTransaction.signature = signature.rawRepresentation.base64EncodedString()
        signedTransaction.status = .signed
        
        return signedTransaction
    }
    
    static func verifySignature(transaction: Transaction, publicKeyData: Data) throws -> Bool {
        guard let signatureBase64 = transaction.signature,
              let signatureData = Data(base64Encoded: signatureBase64) else {
            throw WalletError.invalidTransaction("Missing signature")
        }
        
        let transactionData = try serializeTransaction(transaction)
        let hash = CryptoUtils.sha256(transactionData)
        
        let publicKey = try P256.Signing.PublicKey(rawRepresentation: publicKeyData)
        let signature = try P256.Signing.ECDSASignature(rawRepresentation: signatureData)
        
        return publicKey.isValidSignature(signature, for: hash)
    }
    
    // Ethereum-style transaction serialization (simplified RLP)
    static func serializeTransaction(_ transaction: Transaction) throws -> Data {
        var data = Data()
        
        // Nonce
        var nonce = UInt64(transaction.nonce)
        data.append(Data(bytes: &nonce, count: MemoryLayout<UInt64>.size))
        
        // To address
        if let toData = transaction.to.data(using: .utf8) {
            data.append(toData)
        }
        
        // Amount (as string bytes for simplicity)
        if let amountData = "\(transaction.amount)".data(using: .utf8) {
            data.append(amountData)
        }
        
        // Fee
        if let feeData = "\(transaction.fee)".data(using: .utf8) {
            data.append(feeData)
        }
        
        // Timestamp
        var timestamp = transaction.timestamp.timeIntervalSince1970
        data.append(Data(bytes: &timestamp, count: MemoryLayout<TimeInterval>.size))
        
        return data
    }
    
    // Sign arbitrary message (for dApp interactions)
    static func signMessage(_ message: String, privateKeyData: Data) throws -> String {
        guard let messageData = message.data(using: .utf8) else {
            throw WalletError.invalidTransaction("Invalid message")
        }
        
        // Ethereum-style personal sign prefix
        let prefix = "\u{19}Ethereum Signed Message:\n\(messageData.count)"
        var prefixedMessage = prefix.data(using: .utf8)!
        prefixedMessage.append(messageData)
        
        let hash = CryptoUtils.sha256(prefixedMessage)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: hash)
        
        return "0x" + CryptoUtils.hexString(from: signature.rawRepresentation)
    }
}

