            }
        }
    }
    
    private let session: URLSession
    private let apiKey: String
    var currentNetwork: Network
    
    init(apiKey: String = "", network: Network = .ethereumSepolia) {
        self.apiKey = apiKey
        self.currentNetwork = network
        
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: config)
    }
    
    // MARK: - Ethereum JSON-RPC Methods
    
    func getBalance(address: String) async throws -> BlockchainBalance {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getBalance",
            "params": [address, "latest"],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let hexBalance = response.result as? String else {
            throw WalletError.networkError("Invalid balance response")
        }
        
        let balance = hexToDecimal(hexBalance)
        return BlockchainBalance(address: address, balance: balance, currency: "ETH")
    }
    
    func getTransactionCount(address: String) async throws -> Int {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionCount",
            "params": [address, "latest"],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let hexCount = response.result as? String else {
            throw WalletError.networkError("Invalid nonce response")
        }
        
        return hexToInt(hexCount)
    }
    
    func getGasPrice() async throws -> Decimal {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_gasPrice",
            "params": [],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let hexPrice = response.result as? String else {
            throw WalletError.networkError("Invalid gas price response")
        }
        
        return hexToDecimal(hexPrice)
    }
    
    func estimateGas(from: String, to: String, value: String) async throws -> Int {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_estimateGas",
            "params": [
                ["from": from, "to": to, "value": value]
            ],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let hexGas = response.result as? String else {
            return 21000 // Default gas for simple transfer
        }
        
        return hexToInt(hexGas)
    }
    
    func sendRawTransaction(signedTxHex: String) async throws -> String {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_sendRawTransaction",
            "params": [signedTxHex],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let txHash = response.result as? String else {
            throw WalletError.networkError("Failed to broadcast transaction")
        }
        
        return txHash
    }
    
    func getTransactionReceipt(txHash: String) async throws -> TransactionReceipt? {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionReceipt",
            "params": [txHash],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let result = response.result as? [String: Any] else {
            return nil // Transaction not yet mined
        }
        
        let status = (result["status"] as? String) == "0x1" ? "success" : "failed"
        let blockNumberHex = result["blockNumber"] as? String
        let blockNumber = blockNumberHex.map { hexToInt($0) }
        
        return TransactionReceipt(hash: txHash, status: status, blockNumber: blockNumber)
    }
    
    func getBlockNumber() async throws -> Int {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_blockNumber",
            "params": [],
            "id": 1
        ]
        
        let response: JSONRPCResponse = try await makeRPCRequest(body: body)
        
        guard let hexBlock = response.result as? String else {
            throw WalletError.networkError("Invalid block number response")
        }
        
        return hexToInt(hexBlock)
    }
    
    // MARK: - Network Request Helper
    
    private func makeRPCRequest<T: Decodable>(body: [String: Any]) async throws -> T {
        let urlString = currentNetwork.rawValue + apiKey
        guard let url = URL(string: urlString) else {
            throw WalletError.networkError("Invalid URL")
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw WalletError.networkError("HTTP error: \((response as? HTTPURLResponse)?.statusCode ?? 0)")
        }
        
        let decoder = JSONDecoder()
        return try decoder.decode(T.self, from: data)
    }
    
    // MARK: - Hex Utilities
    
    private func hexToDecimal(_ hex: String) -> Decimal {
        var hex = hex
        if hex.hasPrefix("0x") { hex = String(hex.dropFirst(2)) }
        guard let intValue = UInt64(hex, radix: 16) else { return 0 }
        // Convert from wei to ETH (divide by 10^18)
        return Decimal(intValue) / Decimal(sign: .plus, exponent: 18, significand: 1)
    }
    
    private func hexToInt(_ hex: String) -> Int {
        var hex = hex
        if hex.hasPrefix("0x") { hex = String(hex.dropFirst(2)) }
        return Int(hex, radix: 16) ?? 0
    }
}

// MARK: - JSON-RPC Response

struct JSONRPCResponse: Decodable {
    let jsonrpc: String
    let id: Int
    let result: Any?
    let error: JSONRPCError?
    
    struct JSONRPCError: Decodable {
        let code: Int
        let message: String
    }
    
    enum CodingKeys: String, CodingKey {
        case jsonrpc, id, result, error
    }
    
    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        jsonrpc = try container.decode(String.self, forKey: .jsonrpc)
        id = try container.decode(Int.self, forKey: .id)
        error = try container.decodeIfPresent(JSONRPCError.self, forKey: .error)
        
        if let stringResult = try? container.decode(String.self, forKey: .result) {
            result = stringResult
        } else if let dictResult = try? container.decode([String: String].self, forKey: .result) {
            result = dictResult
        } else {
            result = nil
        }
    }
}

// MARK: - Wallet Error

enum WalletError: LocalizedError {
    case keychainError(String)
    case keyGenerationFailed(String)
    case invalidTransaction(String)
    case networkError(String)
    case insufficientFunds
    case invalidAddress
    case walletNotFound
    
    var errorDescription: String? {
        switch self {
        case .keychainError(let msg): return "Keychain Error: \(msg)"
        case .keyGenerationFailed(let msg): return "Key Generation Failed: \(msg)"
        case .invalidTransaction(let msg): return "Invalid Transaction: \(msg)"
        case .networkError(let msg): return "Network Error: \(msg)"
        case .insufficientFunds: return "Insufficient funds"
        case .invalidAddress: return "Invalid address"
        case .walletNotFound: return "Wallet not found"
        }
    }
}

// MARK: - Wallet Manager (Main Service)

@MainActor
final class WalletManager: ObservableObject {
    
    @Published var wallets: [Wallet] = []
    @Published var currentWallet: Wallet?
    @Published var balance: BlockchainBalance?
    @Published var transactions: [Transaction] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var mnemonicPhrase: [String]?
    
    let blockchainService: BlockchainService
    private let keychainManager = KeychainManager.shared
    private let walletsKey = "stored_wallets"
    
    init(blockchainService: BlockchainService = BlockchainService()) {
        self.blockchainService = blockchainService
        loadWallets()
    }
    
    // MARK: - Wallet Creation
    
    func createNewWallet(name: String) async throws -> Wallet {
        isLoading = true
        defer { isLoading = false }
        
        // Generate mnemonic
        let mnemonic = KeyGenerator.generateMnemonic()
        self.mnemonicPhrase = mnemonic
        
        // Derive seed from mnemonic
        let seed = KeyGenerator.seedFromMnemonic(mnemonic)
        
        // Generate key pair from seed
        let keyPair = try KeyGenerator.generateKeyPairFromSeed(seed)
        
        // Store private key in Keychain
        try keychainManager.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        // Create wallet object
        let wallet = Wallet(
            id: UUID(),
            name: name,
            address: keyPair.address,
            createdAt: Date(),
            publicKeyHex: CryptoUtils.hexString(from: keyPair.publicKey)
        )
        
        wallets.append(wallet)
        currentWallet = wallet
        saveWallets()
        
        return wallet
    }
    
    func importWallet(name: String, mnemonic: [String]) async throws -> Wallet {
        isLoading = true
        defer { isLoading = false }
        
        let seed = KeyGenerator.seedFromMnemonic(mnemonic)
        let keyPair = try KeyGenerator.generateKeyPairFromSeed(seed)
        
        try keychainManager.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        let wallet = Wallet(
            id: UUID(),
            name: name,
            address: keyPair.address,
            createdAt: Date(),
            publicKeyHex: CryptoUtils.hexString(from: keyPair.publicKey)
        )
        
        wallets.append(wallet)
        currentWallet = wallet
        saveWallets()
        
        return wallet
    }
    
    func importWalletFromPrivateKey(name: String, privateKeyHex: String) async throws -> Wallet {
        isLoading = true
        defer { isLoading = false }
        
        guard let privateKeyData = CryptoUtils.data(fromHex: privateKeyHex) else {
            throw WalletError.keyGenerationFailed("Invalid private key hex")
        }
        
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let address = "0x" + CryptoUtils.hexString(from: CryptoUtils.keccak256(publicKeyData).suffix(20))
        
        try keychainManager.storePrivateKey(privateKeyData, forAddress: address)
        
        let wallet = Wallet(
            id: UUID(),
            name: name,
            address: address,
            createdAt: Date(),
            publicKeyHex: CryptoUtils.hexString(from: publicKeyData)
        )
        
        wallets.append(wallet)
        currentWallet = wallet
        saveWallets()
        
        return wallet
    }
    
    // MARK: - Transaction Operations
    
    func sendTransaction(to: String, amount: Decimal) async throws -> Transaction {
        guard let wallet = currentWallet else {
            throw WalletError.walletNotFound
        }
        
        isLoading = true
        defer { isLoading = false }
        
        // Validate address
        guard isValidAddress(to) else {
            throw WalletError.invalidAddress
        }
        
        // Get nonce
        let nonce = try await blockchainService.getTransactionCount(address: wallet.address)
        
        // Get gas price
        let gasPrice = try await blockchainService.getGasPrice()
        
        // Create transaction
        var transaction = Transaction(
            id: UUID(),
            from: wallet.address,
            to: to,
            amount: amount,
            fee: gasPrice * Decimal(21000),
            nonce: nonce,
            timestamp: Date(),
            status: .pending
        )
        
        // Check balance
        if let currentBalance = balance, currentBalance.balance < amount + transaction.fee {
            throw WalletError.insufficientFunds
        }
        
        // Get private key and sign
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: wallet.address)
        transaction = try TransactionSigner.signTransaction(transaction, privateKeyData: privateKeyData)
        
        // Broadcast transaction
        if let signedTxData = transaction.signature {
            let txHash = try await blockchainService.sendRawTransaction(signedTxHex: "0x" + signedTxData)
            transaction.hash = txHash
            transaction.status = .broadcast
        }
        
        transactions.insert(transaction, at: 0)
        saveTransactions()
        
        // Refresh balance
        try await refreshBalance()
        
        return transaction
    }
    
    func signMessage(_ message: String) async throws -> String {
        guard let wallet = currentWallet else {
            throw WalletError.walletNotFound
        }
        
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: wallet.address)
        return try TransactionSigner.signMessage(message, privateKeyData: privateKeyData)
    }
    
    // MARK: - Balance & State
    
    func refreshBalance() async throws {
        guard let wallet = currentWallet else { return }
        
        isLoading = true
        defer { isLoading = false }
        
        balance = try await blockchainService.getBalance(address: wallet.address)
    }
    
    func checkTransactionStatus(_ transaction: Transaction) async throws -> Transaction {
        guard let hash = transaction.hash else { return transaction }
        
        var updatedTx = transaction
        if let receipt = try await blockchainService.getTransactionReceipt(txHash: hash) {
            updatedTx.status = receipt.status == "success" ? .confirmed : .failed
        }
        
        // Update in transactions list
        if let index = transactions.firstIndex(where: { $0.id == transaction.id }) {
            transactions[index] = updatedTx
            saveTransactions()
        }
        
        return updatedTx
    }
    
    // MARK: - Wallet Management
    
    func deleteWallet(_ wallet: Wallet) throws {
        try keychainManager.deletePrivateKey(forAddress: wallet.address)
        wallets.removeAll { $0.id == wallet.id }
        
        if currentWallet?.id == wallet.id {
            currentWallet = wallets.first
        }
        
        saveWallets()
    }
    
    func selectWallet(_ wallet: Wallet) {
        currentWallet = wallet
        balance = nil
        Task {
            try? await refreshBalance()
        }
    }
    
    // MARK: - Validation
    
    func isValidAddress(_ address: String) -> Bool {
        // Ethereum address validation
        if address.hasPrefix("0x") {
            let hex = String(address.dropFirst(2))
            return hex.count == 40 && hex.allSatisfy { $0.isHexDigit }
        }
        // Bitcoin address basic validation
        return address.count >= 25 && address.count <= 62
    }
    
    // MARK: - Persistence
    
    private func saveWallets() {
        if let data = try? JSONEncoder().encode(wallets) {
            UserDefaults.standard.set(data, forKey: walletsKey)
        }
    }
    
    private func loadWallets() {
        if let data = UserDefaults.standard.data(forKey: walletsKey),
           let wallets = try? JSONDecoder().decode([Wallet].self, from: data) {
            self.wallets = wallets
            self.currentWallet = wallets.first
        }
    }
    
    private func saveTransactions() {
        if let data = try? JSONEncoder().encode(transactions) {
            UserDefaults.standard.set(data, forKey: "stored_transactions")
        }
    }
    
    private func loadTransactions() {
        if let data = UserDefaults.standard.data(forKey: "stored_transactions"),
           let transactions = try? JSONDecoder().decode([Transaction].self, from: data) {
            self.transactions = transactions
        }
    }
}

// MARK: - String Extension

extension String {
    func leftPadded(to length: Int, with character: Character = "0") -> String {
        let padding = String(repeating: character, count: max(0, length - count))
        return padding + self
    }
}

