// MARK: - Import Wallet View

struct ImportWalletView: View {
    @EnvironmentObject var walletManager: WalletManager
    @Environment(\.dismiss) var dismiss
    @State private var walletName = ""
    @State private var importMethod = 0
    @State private var mnemonicText = ""
    @State private var privateKeyText = ""
    @State private var isImporting = false
    @State private var error: String?
    
    var body: some View {
        NavigationView {
            Form {
                Section("Wallet Name") {
                    TextField("Imported Wallet", text: $walletName)
                }
                
                Picker("Import Method", selection: $importMethod) {
                    Text("Recovery Phrase").tag(0)
                    Text("Private Key").tag(1)
                }
                .pickerStyle(.segmented)
                .padding(.vertical)
                
                if importMethod == 0 {
                    Section("Recovery Phrase") {
                        TextEditor(text: $mnemonicText)
                            .frame(minHeight: 100)
                        Text("Enter your 12 or 24 word recovery phrase separated by spaces")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                } else {
                    Section("Private Key") {
                        SecureField("Enter private key (hex)", text: $privateKeyText)
                    }
                }
                
                Section {
                    Button(action: importWallet) {
                        if isImporting {
                            ProgressView()
                        } else {
                            Text("Import Wallet")
                        }
                    }
                    .disabled(walletName.isEmpty || isImporting)
                }
                
                if let error = error {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle("Import Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    func importWallet() {
        isImporting = true
        error = nil
        
        Task {
            do {
                if importMethod == 0 {
                    let words = mnemonicText.trimmingCharacters(in: .whitespacesAndNewlines)
                        .components(separatedBy: .whitespaces)
                        .filter { !$0.isEmpty }
                    
                    guard words.count == 12 || words.count == 24 else {
                        error = "Please enter 12 or 24 words"
                        isImporting = false
                        return
                    }
                    
                    _ = try await walletManager.importWallet(name: walletName, mnemonic: words)
                } else {
                    _ = try await walletManager.importWalletFromPrivateKey(
                        name: walletName,
                        privateKeyHex: privateKeyText.trimmingCharacters(in: .whitespacesAndNewlines)
                    )
                }
                dismiss()
            } catch {
                self.error = error.localizedDescription
            }
            isImporting = false
        }
    }
}

// MARK: - Send View

struct SendView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var recipientAddress = ""
    @State private var amount = ""
    @State private var isSending = false
    @State private var showConfirmation = false
    @State private var error: String?
    @State private var successTx: Transaction?
    
    var body: some View {
        NavigationView {
            Form {
                if walletManager.currentWallet == nil {
                    Section {
                        Text("Please create or import a wallet first")
                            .foregroundColor(.secondary)
                    }
                } else {
                    Section("From") {
                        if let wallet = walletManager.currentWallet {
                            VStack(alignment: .leading) {
                                Text(wallet.name)
                                    .font(.headline)
                                Text(wallet.address)
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                                if let balance = walletManager.balance {
                                    Text("Balance: \(balance.balance as NSDecimalNumber) \(balance.currency)")
                                        .font(.caption)
                                        .foregroundColor(.blue)
                                }
                            }
                        }
                    }
                    
                    Section("Recipient") {
                        TextField("0x... or address", text: $recipientAddress)
                            .autocapitalization(.none)
                            .disableAutocorrection(true)
                        
                        if !recipientAddress.isEmpty && !walletManager.isValidAddress(recipientAddress) {
                            Text("Invalid address format")
                                .font(.caption)
                                .foregroundColor(.red)
                        }
                    }
                    
                    Section("Amount") {
                        HStack {
                            TextField("0.0", text: $amount)
                                .keyboardType(.decimalPad)
                            Text("ETH")
                                .foregroundColor(.secondary)
                        }
                    }
                    
                    Section {
                        Button(action: { showConfirmation = true }) {
                            HStack {
                                Spacer()
                                if isSending {
                                    ProgressView()
                                } else {
                                    Text("Send Transaction")
                                        .bold()
                                }
                                Spacer()
                            }
                        }
                        .disabled(
                            recipientAddress.isEmpty ||
                            amount.isEmpty ||
                            !walletManager.isValidAddress(recipientAddress) ||
                            isSending
                        )
                    }
                    
                    if let error = error {
                        Section {
                            Text(error)
                                .foregroundColor(.red)
                        }
                    }
                    
                    if let tx = successTx {
                        Section("Transaction Sent") {
                            VStack(alignment: .leading) {
                                Text("Hash: \(tx.hash ?? "Pending")")
                                    .font(.caption)
                                Text("Status: \(tx.status.rawValue)")
                                    .font(.caption)
                                    .foregroundColor(.green)
                            }
                        }
                    }
                }
            }
            .navigationTitle("Send")
            .alert("Confirm Transaction", isPresented: $showConfirmation) {
                Button("Cancel", role: .cancel) {}
                Button("Send") { sendTransaction() }
            } message: {
                Text("Send \(amount) ETH to \(recipientAddress.prefix(20))...?")
            }
        }
    }
    
    func sendTransaction() {
        isSending = true
        error = nil
        successTx = nil
        
        Task {
            do {
                guard let decimalAmount = Decimal(string: amount) else {
                    error = "Invalid amount"
                    isSending = false
                    return
                }
                
                let tx = try await walletManager.sendTransaction(to: recipientAddress, amount: decimalAmount)
                successTx = tx
                recipientAddress = ""
                amount = ""
            } catch {
                self.error = error.localizedDescription
            }
            isSending = false
        }
    }
}

