struct TransactionRow: View {
    let transaction: Transaction
    
    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack {
                Image(systemName: "arrow.up.circle.fill")
                    .foregroundColor(.red)
                
                VStack(alignment: .leading) {
                    Text("To: \(String(transaction.to.prefix(16)))...")
                        .font(.body.bold())
                    Text("\(transaction.amount as NSDecimalNumber) ETH")
                        .font(.subheadline)
                }
                
                Spacer()
                
                StatusBadge(status: transaction.status)
            }
            
            if let hash = transaction.hash {
                Text("Tx: \(String(hash.prefix(20)))...")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Text(transaction.timestamp, style: .relative)
                .font(.caption)
                .foregroundColor(.secondary)
        }
        .padding(.vertical, 4)
    }
}

struct StatusBadge: View {
    let status: Transaction.TransactionStatus
    
    var color: Color {
        switch status {
        case .pending: return .yellow
        case .signed: return .blue
        case .broadcast: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }
    
    var body: some View {
        Text(status.rawValue.capitalized)
            .font(.caption.bold())
            .padding(.horizontal, 8)
            .padding(.vertical, 4)
            .background(color.opacity(0.2))
            .foregroundColor(color)
            .cornerRadius(8)
    }
}

